struct hash<char*>
	{
		size_t operator()(const char* p) const
		{
			uint32_t c, result = 2166136261U;   // FNV1 hash. Perhaps the best string hash. Intentionally uint32_t instead of size_t, so the behavior is the same regardless of size.
