inline void int128_t_base::OperatorXOR(const int128_t_base& value1, const int128_t_base& value2, int128_t_base& result)
{
	result.mPart0 = (value1.mPart0 ^ value2.mPart0);
	result.mPart1 = (value1.mPart1 ^ value2.mPart1);
